INSERT INTO `all_papers_records` VALUES ('传统杵针合麦粒灸治疗卵泡发育不良验案1则_张雪梅.pdf','36岁',NULL,'近2年月经周期延长，2～3d/40～50d，月经量少而质薄，经色暗淡，偶有痛经；末次月经2015年8月10日，3d净，色淡暗，量少','结婚2年未避孕，一直未孕，无生育史',NULL,'神清，神疲乏力，面色晦暗，小腹坠胀，失眠，夜尿频，大便尚可，舌暗红、苔薄白，脉细弱','2015年1月10日外院做输卵管造影术后显示双侧输卵管通畅；曾使用促排卵药物克罗米酚及绒毛膜促性腺激素治疗，3个月经周期均未受孕','2015年1月14日（月经第3天）行性激素5项检查：FSH 15.24IU/L，LH 10.25IU/L，E2 23.48pg/ml，P 1.9nmol/L，PRL 26.8ng/ml；2月24及4月3日复查FSH值均＞12IU/L。治疗2个疗程后（12月8日）复查：FSH 8.94IU/L，LH 9.75IU/L，E2 21.35pg/ml，P 0.79nmol/L，PRL 23.5ng/ml','治疗前：卵泡发育超声监测排卵3个周期，均提示有排卵，卵泡15～16mm时排出，提示小卵泡周期。治疗后：第2个疗程月经周期第22天出现成熟卵泡，卵泡达18mm以上，外形饱满，卵泡位于卵巢表面，并向外突出；第3个疗程超声检测优势卵泡存在，卵泡达18mm以上','治疗2个疗程后，于12月8日复查性激素5项及卵泡发育超声监测；患者进行第3个疗程，超声检测优势卵泡存在，卵泡达18mm以上，于2016年2月7日告知成功受孕','卵泡发育不良型不孕症','不孕（脾肾阳虚，气血不足证）','健脾温肾，益气养血',NULL,'杵针：命门八阵、关元八阵、河车路（命门至长强段）、气穴、然谷、三阴交、足三里；艾盒灸：四满、关元、中极、气海、石门、肾俞、次髎、中髎、命门；麦粒灸：独阴、足临泣',NULL,'暂停西药治疗（曾用克罗米酚、绒毛膜促性腺激素）','成功受孕',NULL,'卵泡发育不良归为“月经失调”“全不产”“无子”等范畴。病机为先天不足，肾气虚弱，或精血亏损，冲任虚衰，胞脉失养。采用传统杵针疗法及灸法达到健脾温肾、益气养血之功，对脾肾阳虚、气血不足型不孕症有较好疗效。'),('王秀宝教授诊疗不孕症经验_陈月玲.pdf','30岁',NULL,'经期下腹胀痛加剧','未避孕未孕3年',NULL,'带下量多、色黄，下腹偶有胀痛，痛处固定，尚可忍受，经期加剧，婚久不孕，舌质暗红有紫斑，苔白腻，脉弦涩','解脲支原体感染病史','尿妊娠试验阳性','双侧输卵管通而不畅-伞端粘连；B超监测卵泡发育；阴道彩超提示宫内早孕','二诊：带下量多，色稍黄，质偏稠；三诊：腰酸、头晕；四诊：优势卵泡已成熟；五诊：下腹胀痛消失，带下量显著减少，色转清稀淡白，感乏力、腰酸','不孕症','不孕症（湿热瘀结证）','清热祛湿止带，化瘀通络；清热利湿，活血化瘀，佐以益气；阴阳并调，育肾通络；育肾温煦，暖宫摄精；行气活血，调畅冲任','蒲皂愈炎汤、孕1方、孕2方、圣愈调冲汤',NULL,'腹腔镜下盆腔粘连分离术＋左侧输卵管修复整形术＋宫腔镜双侧输卵管插管通液术',NULL,'临床妊娠（宫内早孕）',NULL,'本案治疗融贯中西，阶段分明，以手术速去“器质之阻”，以中药调“功能之乱”，术后予以“三阶助孕法”，辅以卵泡监测精准指导，最终患者受孕。'),('补肾健脾调冲法辨治女性不孕症验案1例_牛阿娜.pdf','33岁',NULL,'平素月经规律，13岁初潮，周期28天，经期3～4天，经量中，色黯红，无明显痛经；末次月经（LMP）2023年2月3日','婚后不避孕2+年未孕，孕产史G0P0，配偶精液检查无殊',NULL,'腰酸，入睡困难，眠浅易醒，大便溏，1～2次/日，舌淡胖、边有齿痕、苔色白、苔质厚腻，脉沉细',NULL,'2022年10月24日抗缪勒管激素（AMH）5.49 ng/mL；2023年5月15日查血HCG 162 IU/L，E2 299.39 pg/mL，P 92.12 nmol/L','2022年11月10日子宫输卵管造影（HSG）提示双侧输卵管通畅；2023年3月25日卵泡监测提示子宫内膜双层1.1 cm，右侧卵巢见一优势卵泡（约2.1 cm×2.1 cm×1.9 cm）；2023年6月10日停经8W+6D超声示宫内见1.4 cm胚芽，心搏可见','2月22日二诊便溏好转，腰酸眠浅仍有；3月13日三诊腰酸好转，夜寐改善，LMP 3月9日；3月25日四诊见优势卵泡，指导同房；4月8日五诊月经后期，HCG<0.1 IU/L；4月22日六诊LMP 4月9日；5月13日自测尿妊娠试验阳性','原发性不孕','不孕症（脾肾两虚证）','补肾健脾，调冲助孕','培土毓麟汤化裁（菟丝子、枸杞子、桑寄生、覆盆子、百合、大枣、太子参、党参、黄芪、炒白术、淮山药、炒白扁豆、姜半夏、姜厚朴、砂仁、绿梅花、炙甘草）；随证加减使用酸枣仁、姜竹茹、北柴胡、广木香、丝瓜络',NULL,'指导同房','人胎盘片、定坤丹','治疗2个月余受孕，随访孕38+周顺产1子，母子康健',NULL,'该案为脾肾两虚型不孕症。肾为主生殖之本，脾为后天之本，脾肾功能正常则冲任得充，男女之精正常搏结故胎孕得成。治疗以补肾健脾、调冲助孕为法，方选培土毓麟汤化裁，以后天补养先天，全方共奏补肾健脾，调冲种子之效。'),('通、补、疏三期序贯调经法治疗不孕症验案二则_陈杨.pdf','26岁',NULL,'12岁月经初潮，平素月经规律，周期28～30天，经期5～7天，量适中，色红，有少量血块。4年前出现经前腰酸、乳房胀满及小腹坠痛，月经来潮1～2天即出现下腹部痉挛性疼痛，可放射至腰骶部及腹股沟，持续至月经结束，严重时伴恶心、呕吐、肛门坠胀感等。','已婚，未避孕未孕2年。配偶身体健康，精液检查正常。性生活尚可，偶有性交疼痛，尤其在月经来潮前更加明显。','性格内敛，沉默少言。','现月经第2天，痛经明显；形体瘦薄，面色发白，痛苦面容，以手捂腹，语声低微，舌胖淡，色紫，边有齿痕，苔白，舌下脉络色暗，脉弦滑。平素常感腰膝酸软、怕冷、头晕乏力，偶有腹胀，食欲一般，大便干燥，2～3天一行，排便无力、量少。','曾自服止疼药、消炎药，但效果欠佳。','血清糖类抗原125（CA 125）水平升高（49 U/mL）；复诊查血人绒毛膜促性腺激素（HCG）5017.5 mIU/mL，孕酮 99.2 nmol/L。','2023年2月盆腔超声示：左侧卵巢内见一大小约4cm×3cm的囊性包块，边界清，内见密集光点，提示卵巢子宫内膜异位囊肿可能。9月13日复查示：宫内早孕，可见20mm×25mm×14mm孕囊，可见胚芽7mm，并见心管搏动。','二诊：月经干净，疼痛减轻，经量增加，色暗红，血块多。三诊：腰膝酸软、疲劳乏力改善，食欲增加，大便顺畅。四诊：头晕乏力等症已无，近期自觉略有烦躁，有乳胀感。五诊：月经第1天，无明显痛经，经量适中，血块较少。后继续采用序贯调经法治疗3个月。','原发性不孕；子宫内膜异位症。','不孕；辨属肾虚肝郁血瘀证。','温肾助阳，理气疏肝，活血止痛。','行经期用逐瘀通经汤化裁（当归、川芎、生地黄、赤芍、牡丹皮、泽兰、益母草、艾叶、炮姜、醋香附、川牛膝、生蒲黄、淡附片、肉苁蓉、锁阳、柴胡、刺蒺藜）；经后期用培元养阴汤化裁（熟地黄、当归、川芎、生白芍、砂仁、生白术、茯苓、党参、丹参、醋香附、泽兰、淫羊藿、锁阳、柏子仁、石菖蒲）；经前期用疏肝育阳汤化裁。',NULL,NULL,NULL,'顺利妊娠。2023年8月29日自测尿HCG弱阳性，后经医院检查确认早孕。2024年5月顺利诞下一子。',NULL,'采用“通、补、疏三期序贯调经法”。行经期重在“通”，以逐瘀通经汤促进内膜脱落与瘀血排出；经后期重在“补”，以培元养阴汤滋补精血、修复内膜；经前期重在“疏”，以疏肝育阳汤调理气机、促进月经来潮。全案体现了因势利导、序贯调理的辨证思路。'),('杜小利治疗卵巢储备功能下降致不孕症验案1则_王雪怡.pdf','32岁',NULL,'11岁月经初潮，周期30天，经期7天。末次月经日期2017年8月5日，系服中药后来潮，经前、经期全身疼痛、腰困，目前月经已推迟20天未行。闭经3年，需注射黄体酮或口服中药方可来潮。','不避孕2年未孕，继发性不孕，孕1产1。',NULL,'恶热，面部烘热，皮肤干燥，咽干苦，欲饮水，腰困，咽阻痰多，便秘，乏力，嗜睡，腹冷。舌尖红，脉弦细。','3年前因过度恼怒后出现突然闭经。','月经第2日（8月6日）测FSH：23.28 mIU/mL，LH：9.08 mIU/mL；甲状腺功能检测：T3、T4、TSH均未见异常；11月6日测尿HCG（+）。','10月23日（月经周期第13天）阴超测排卵：右侧卵泡17 mm×15 mm。','10月9日二诊：药后3日BBT上升，随后未用黄体酮月经来潮，量中，色黯红，伴少量血块及内膜样物，经期腰酸甚并腹痛，口苦、腹凉、咽部自觉痰阻。10月23日三诊：诸症已明显减轻，但仍感口干，皮肤干燥，乏力嗜睡，下肢肿胀。11月6日四诊：月经周期第33天，测BBT已上升17天，测尿HCG（+）。','卵巢储备功能下降，继发性不孕症','不孕（肝郁肾阴虚夹瘀证）','滋肾养阴，疏肝降火，化痰活血；后期补肝肾益冲任保胎。','初诊方：黄芪30 g，生地黄、熟地黄各18 g，柴胡、合欢皮、当归、白芍、莪术各15 g，石菖蒲、郁金、陈皮各12 g，知母、黄柏、龙胆草、甘草各10 g，肉桂3 g。二诊方：初诊方去当归、石菖蒲、合欢皮，加山萸肉10 g，浙贝母12 g，女贞子15 g，丹参18 g。三诊方：二诊方去浙贝母、肉桂、熟地黄，知母12 g，黄芪45 g，加牡丹皮10 g，茯苓皮18 g。四诊保胎方：黄芪30 g，太子参、川续断各18 g，菟丝子、白芍、陈皮各15 g，桑葚、枸杞子各12 g，山萸肉、当归、鹿角霜、甘草各10 g。',NULL,NULL,'氯米芬，月经周期第5天起服用，每次50 mg，每日1次，连服5日。','治疗后月经来潮，诸症减轻，最终获得妊娠。',NULL,'该患者原由情志因素引发，导致肝郁化火，灼伤肾阴，天癸枯竭，冲任亏损，从而形成肝郁肾阴虚之证。本虚标实，以肾阴虚为主，但郁火仍存，且兼夹痰瘀。治疗上采用滋肾养阴、疏肝泻火兼化痰活血之法。治疗中结合使用西药氯米芬共同促排卵。月经中后期结合阴超提示及BBT监测，调整方药加强补气养肾，最终成功受孕。'),('经方治验医案5则_代波.pdf','23岁',NULL,NULL,'诊前已有3次流产史，皆在孕3个月左右',NULL,'现妊娠2月余，呕吐不止，面黄肌瘦，伴头昏，心下冷痛，纳差，便溏，小便不利，苔白而润，津液满口欲滴，脉滑','已有3次流产史',NULL,NULL,'二诊：服药后小便利，呕吐减轻，饮食增加。三诊：服药后呕吐停止，饮食基本正常，头昏消失，大便成型，苔薄白，口内津液明显减少。','习惯性流产','中焦脾胃阳虚，膀胱气化不利','化气行水安胎，温中祛寒，补气健脾','五苓散加减（桂枝6g、砂仁6g、白术15g、茯苓15g、猪苓15g、泽泻10g、生姜10g）；二诊合用理中汤（党参20g、干姜10g、甘草5g）',NULL,NULL,NULL,'妊娠9月产一男婴，健康',NULL,'本案因中焦脾胃虚寒致升降失职，不能摄津，津上溢于口；水湿下犯膀胱，则气化失司，小便不利。当以温中祛寒，补气健脾，以五苓散治标，理中汤治本。'),('陈慧侬教授治疗薄型子宫内膜不孕症经验撷菁_秦琴琴.pdf','30岁',NULL,'月经量减少3年，色淡，质稀，有痛经，经期2~3 d，周期30~35 d，末次月经2022年11月6日','未避孕未孕1年',NULL,'腰膝酸软，乏力健忘，面色晦暗，纳可，寐差，大便正常，夜尿多。舌质紫暗，边有瘀点，苔白，脉沉涩','孕1产0；2022年3月行输卵管造影提示双侧输卵管通畅','性激素六项检查结果正常；男方精液检查正常；六诊实验室检查孕酮20.14 ng/ml，绒毛膜促性腺激素 547 mIU/ml','初诊：多次B超检查提示成熟卵泡排出后，子宫内膜厚度均<0.7 cm；二诊：卵泡 2.0 cm×1.8 cm，内膜厚度 0.8 cm；五诊：卵泡已排','二诊：乏力好转，腰膝酸软减轻，睡眠好转；三诊：腰膝酸软仍有，乏力缓解，睡眠好转；四诊：月经量恢复正常，色暗红，无血块，无痛经及腰酸；五诊：予上方加味；六诊：月经逾期未至，证实已怀孕','薄型子宫内膜不孕症','不孕症（肾精不足兼血瘀证）','补肾益精、养血化瘀','加味五子衍宗方（菟丝子、五味子、枸杞子、覆盆子、车前子、桑椹子、熟地黄、益母草、当归、白术、茯神、鹿角胶、紫河车）；随症加减使用蛤蚧、桃仁、红花、川芎、赤芍、茯苓、续断、桑寄生、阿胶',NULL,NULL,NULL,'治愈，成功受孕',NULL,'本案病机为肾精不足兼血瘀证，治疗以补肾益精、养血化瘀为法。陈教授主张根据月经周期阴阳气血变化调整用药：经后期大补精血、滋养冲任；经间期加入蛤蚧助肾阳促排卵；经前期加入桃红四物汤加减以活血通络、清理胞宫；黄体期加用寿胎丸增强肾气以改善内膜容受性。');
/*!40000 ALTER TABLE `all_papers_records` ENABLE KEYS */;

--
-- Table structure for table `edges`
--

DROP TABLE IF EXISTS `edges`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `edges` (
  `id` char(40) COLLATE utf8mb4_unicode_ci NOT NULL,
  `source_id` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `target_id` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `edge_type` enum('paper-paper','paper-record','record-record') COLLATE utf8mb4_unicode_ci NOT NULL,
  `similarity_score` decimal(6,4) NOT NULL,
  `raw_score` decimal(12,8) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_edges_type_pair` (`edge_type`,`source_id`,`target_id`),
  KEY `idx_edges_source_score` (`source_id`,`similarity_score`),
  KEY `idx_edges_target_score` (`target_id`,`similarity_score`),
  KEY `idx_edges_seed_expand` (`source_id`,`target_id`),
  CONSTRAINT `fk_edges_source` FOREIGN KEY (`source_id`) REFERENCES `nodes` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_edges_target` FOREIGN KEY (`target_id`) REFERENCES `nodes` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `chk_edges_score_range` CHECK (((`similarity_score` >= 0.0000) and (`similarity_score` <= 1.0000)))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

